    public static string Format(string messageId, string camelPropertyName)
    {
        if (!TryFormat(messageId, camelPropertyName, out var key))
        {
            throw new InvalidOperationException($"No field id for {messageId}:{camelPropertyName}");
        }

        return key;
    }

    public static bool TryFormat(string messageId, string camelPropertyName, out string key)
    {
        var lookup = messageId + ":" + camelPropertyName;
        if (!FieldIds.TryGetValue(lookup, out var id))
        {
            key = "";
            return false;
        }

        key = messageId + "_" + id.ToString("D3");
        return true;
    }

    public static string Alias(string aliasName) => Format("997", aliasName);

